#include <stdio.h>
int add(int a, int b) { return a + b; }
int sub(int a, int b) { return a - b; }
int mul(int a, int b) { return a * b; }
int div(int a, int b) { return (b != 0) ? a / b : 0; }
int main() {
    int (*ops[])(int, int) = {add, sub, mul, div};
    int a, b, choice;
    printf("Enter two numbers: ");
    scanf("%d %d", &a, &b);
    printf("Choose operation: 1.Add 2.Sub 3.Mul 4.Div\n");
    scanf("%d", &choice);
    if (choice >= 1 && choice <= 4) {
        int result = ops[choice-1](a, b);
        printf("Result: %d\n", result);
    } else printf("Invalid choice\n");
    return 0;
}
```

```c
#include <stdio.h>
#include <stdlib.h>
#include <string.h>

typedef struct {
    int roll;
    char name[50];
    float marks;
} Student;

void addRecord() {
    Student s;
    FILE *fp = fopen("students.dat", "ab");
    printf("Enter roll, name, marks: ");
    scanf("%d %s %f", &s.roll, s.name, &s.marks);
    fwrite(&s, sizeof(Student), 1, fp);
    fclose(fp);
}

void displayAll() {
    Student s;
    FILE *fp = fopen("students.dat", "rb");
    if (!fp) { printf("No records\n"); return; }
    printf("Roll\tName\tMarks\n");
    while (fread(&s, sizeof(Student), 1, fp)) {
        printf("%d\t%s\t%.2f\n", s.roll, s.name, s.marks);
    }
    fclose(fp);
}

void searchRecord(int roll) {
    Student s;
    FILE *fp = fopen("students.dat", "rb");
    if (!fp) { printf("No records\n"); return; }
    int found = 0;
    while (fread(&s, sizeof(Student), 1, fp)) {
        if (s.roll == roll) {
            printf("Found: %d %s %.2f\n", s.roll, s.name, s.marks);
            found = 1;
            break;
        }
    }
    if (!found) printf("Not found\n");
    fclose(fp);
}

void deleteRecord(int roll) {
    Student s;
    FILE *fp = fopen("students.dat", "rb");
    FILE *temp = fopen("temp.dat", "wb");
    if (!fp) { printf("No records\n"); return; }
    int found = 0;
    while (fread(&s, sizeof(Student), 1, fp)) {
        if (s.roll != roll) {
            fwrite(&s, sizeof(Student), 1, temp);
        } else found = 1;
    }
    fclose(fp);
    fclose(temp);
    remove("students.dat");
    rename("temp.dat", "students.dat");
    if (found) printf("Deleted\n");
    else printf("Not found\n");
}

int main() {
    int choice, roll;
    while (1) {
        printf("\n1.Add 2.Display 3.Search 4.Delete 5.Exit\nChoice: ");
        scanf("%d", &choice);
        switch(choice) {
            case 1: addRecord(); break;
            case 2: displayAll(); break;
            case 3: printf("Roll: "); scanf("%d", &roll); searchRecord(roll); break;
            case 4: printf("Roll: "); scanf("%d", &roll); deleteRecord(roll); break;
            case 5: exit(0);
            default: printf("Invalid\n");
        }
    }
    return 0;
}
```
